INSERT INTO poses (pose_id, canonical_name, common_name, difficulty_rank, instructor_cue_priority, lineage_source, fyt100_session_ref, aeo_summary) VALUES ('in_sanskrit_the_word_chakra_can_be_translated_into_wheel_or_turning_in_the_yogic_interpretation', 'In Sanskrit the word chakra can be translated into “wheel” or “turning.” In the yogic interpretation,', 'In Sanskrit the word chakra can be translated into “wheel” or “turning.” In the yogic interpretation,', 3, '', '', '', 'the chakras are based on the concept of a vortex and are visually portrayed as a lotus flower. According to various Eastern yogic spiritual practices such as Hinduism and Tantric Buddhism. chakras are described as wheels or rings of energy found in the subtle (non-physical) body; the culmination of the mind, intelligence, and ego, which influences the gross physical body. Within this subtle body there are energy channels called nadis that carry the life force or vital energy (prana). The mainnadi that runs through the chakras is called the sushumna (brahma) nadi. The sushumna joins two other important nadis (ida and pingala) together at the first and seventh chakras. The diameter of a singular nadi is believed to be no thicker than a thousandth of a hair’s width and is located along the spine.');
INSERT INTO pose_keywords (pose_id, keyword) VALUES ('in_sanskrit_the_word_chakra_can_be_translated_into_wheel_or_turning_in_the_yogic_interpretation', 'In Sanskrit the word chakra can be translated into “wheel” or “turning.” In the yogic interpretation,');
INSERT INTO pose_benefits (pose_id, tag, weight) VALUES ('in_sanskrit_the_word_chakra_can_be_translated_into_wheel_or_turning_in_the_yogic_interpretation', 'GeneralWellness', 0.5);
