INSERT INTO pose_keywords (pose_id, keyword) VALUES ('there_are_various_opinions_on_how_many_chakras_there_are_but_it_is_generally_agreed_that_chakras', 'There are various opinions on how many chakras there are, but it is generally agreed that chakras');
